var e=[{id:`L5_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`으아, 너무 어둡네요.`,JPN:`うわあ、暗すぎますわ。`,ENG:`Whoa, it's so dark.`,TWN:`呃，這裡太暗了。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`그러게. 이 안은 아무것도 안 보이네.`,JPN:`そうだな。この中は何も見えない。`,ENG:`Yeah. I can't see anything.`,TWN:`是啊，我什麼都看不到。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`히끅-!`,JPN:`ひっくー！`,ENG:`*Hiccup!*`,TWN:`嗝——！`},stage:{bg:`BLACK`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>함내 시동 권한자 탑승을 확인. 전원을 공급합니다.</color>`,JPN:`<color=#ffd34c>艦内に始動権限者の搭乗を確認。電源を供給します。</color>`,ENG:`<color=#ffd34c>Authorized personnel on board. Standby mode, disabled.</color>`,TWN:`<color=#ffd34c>確認艦船啟動授權者。即將接通電源。</color>`},stage:{bg:`CORRIDOR_04`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}},sfx:`FX_CUTSCEN_SYS_START2`},{id:`L10_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`아, 불 들어왔다.`,JPN:`あ、明かりがついた。`,ENG:`Oh, the lights are on.`,TWN:`啊，燈亮了。`},stage:{bg:`CORRIDOR_04`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L11_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`히끅- 우으으…`,JPN:`ひっくーううう……`,ENG:`*Hiccup!* Ngh...`,TWN:`嗝——呃……`},stage:{bg:`CORRIDOR_04`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`탈리, 방금 명치가 번쩍거렸는데… 괜찮은 거 맞지?`,JPN:`タリー、今みぞおちが光ったんだけど……本当に大丈夫なのか？`,ENG:`Tallie, something just flashed inside you... You're okay, right?`,TWN:`塔莉，你的心口剛才一閃閃的……你沒事吧？`},stage:{bg:`CORRIDOR_04`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L13_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`소, 속이 별로 안 좋긴 하지만 괜찮아요! 얼른 조종실을 찾아보죠!`,JPN:`あ、あまり気分が良くないんですけど、大丈夫ですわ！　早く操縦室を探しましょう！`,ENG:`I-I don't feel so good, but I think I'm okay! Let's go find the flight deck!`,TWN:`我感覺不太舒服，不過沒關係，我們快去找駕駛艙吧！`},stage:{bg:`CORRIDOR_04`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L16_1`,type:`dialog`,speaker:`CANNON_SHARKS_NULL_NULL`,text:{KOREA:`꺄아아! 복도가 기운다아!`,JPN:`きゃああ！　廊下が傾いたぁ！`,ENG:`Kyaah! The corridor's slanted!`,TWN:`啊啊啊！走廊傾斜了！`},stage:{bg:`CORRIDOR_04`,bgm:`THEMA_EXCUTE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CANNON_SHARKS_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`DAGGER_SHARKS_NULL_NULL`,text:{KOREA:`이런! 내 손잡아!`,JPN:`危ない！　あたしの手を握れ！`,ENG:`Yikes! Grab my hand!`,TWN:`啊！抓住我的手！`},stage:{bg:`CORRIDOR_04`,bgm:`THEMA_EXCUTE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DAGGER_SHARKS_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`PIRATE_FRONTBAY_JACK_CREW`,text:{KOREA:`크라켄이 함선을 노리고 공격합니다!`,JPN:`クラーケンが艦船を狙って攻撃しています！`,ENG:`Kraken is attacking the ship!`,TWN:`克拉肯正在瞄準艦船發動攻擊！`},stage:{bg:`FRONTBAY_DECK_FOG`,bgm:`THEMA_EXCUTE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`PIRATE_FRONTBAY_JACK_CREW`,face:`UNIT_SERIOUS`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`PIRATE_FRONTBAY_JACK_BOSUN`,text:{KOREA:`함선이 가동되자마자 놈은 저걸 위험하다고 판단한 모양이군요.`,JPN:`艦船が稼働しだして、ヤツはあれが危険だと判断したようですな。`,ENG:`It must instinctively know how dangerous that ship is to attack it as soon as it turned on.`,TWN:`艦船一開始運行，那傢伙就本能的覺得有危險。`},stage:{bg:`FRONTBAY_DECK_FOG`,bgm:`THEMA_EXCUTE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JACK_FRONTBAY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`JACK_FRONTBAY_NULL_NULL`,text:{KOREA:`시선을 돌려라! 선수포 발사!`,JPN:`視線を向けろ！　船首砲、発射！`,ENG:`Distract it! Fire the cannons!`,TWN:`轉移他的視線！開火！`},stage:{bg:`FRONTBAY_DECK_FOG`,bgm:`THEMA_EXCUTE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JACK_FRONTBAY_NULL_NULL`,face:`UNIT_IDLE`},R:null}},sfx:`FX_CUTSCEN_NOISE_RUSTLE_04`},{id:`L25_1`,type:`dialog`,speaker:`PIRATE_FRONTBAY_JACK_CREW`,text:{KOREA:`선수포 발사!!`,JPN:`船首砲、発射！！`,ENG:`Firing the cannon!`,TWN:`大砲發射！！`},stage:{bg:`FRONTBAY_DECK_FOG`,bgm:`THEMA_EXCUTE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`JACK_FRONTBAY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};